mapper.select:
SELECT COUNT(*)
FROM review_record
WHERE user_id = #{userId}
  AND schedule_id = #{scheduleId}

SELECT COUNT(*)
FROM review_record
WHERE user_id = #{userId}
  AND reviewed_at  >=  #{start}
  AND reviewed_at  <  #{end}

SELECT
    IFNULL((
        SELECT COUNT(DISTINCT schedule_id)
        FROM review_record
        WHERE user_id = #{userId}
          AND DATE(reviewed_at) = #{date}
          AND schedule_id IS NOT NULL
    ), 0)
    + IFNULL((
        SELECT COUNT(*)
        FROM (
            SELECT task_id
            FROM review_record
            WHERE user_id = #{userId}
              AND DATE(reviewed_at) = #{date}
              AND schedule_id IS NULL
            GROUP BY task_id
        ) legacy_per_task
    ), 0)
